SELECT ManifestContainers.Manifest, Facilities.FacilityName, Manifests.StatusIND, Manifests.StatusDate, Orders.DivisionCD, Orders.OrderNumber, OrderLineItemReleases.LineItemID, OrderLineItemReleases.StyleCd, OrderLineItemReleases.ColorCD, OrderLineItemReleases.SizeCD, OrderLineItemReleases.AttributeCD, Sum(Containers.Quantity) AS 'Sum of Quantity'
FROM OneSource.dbo.Containers Containers, OneSource.dbo.Facilities Facilities, OneSource.dbo.ManifestContainers ManifestContainers, OneSource.dbo.Manifests Manifests, OneSource.dbo.OrderLineItemContainers OrderLineItemContainers, OneSource.dbo.OrderLineItemReleases OrderLineItemReleases, OneSource.dbo.OrderLineItems OrderLineItems, OneSource.dbo.Orders Orders
WHERE ManifestContainers.ContainerID = Containers.ContainerID AND OrderLineItemContainers.ContainerID = Containers.ContainerID AND OrderLineItemContainers.ContainerID = ManifestContainers.ContainerID AND Orders.OrderID = OrderLineItemContainers.OrderID AND OrderLineItemReleases.LineItemID = OrderLineItemContainers.LineItemID AND OrderLineItemReleases.OrderID = OrderLineItemContainers.OrderID AND OrderLineItemReleases.OrderID = Orders.OrderID AND OrderLineItems.LineItemID = OrderLineItemContainers.LineItemID AND OrderLineItems.LineItemID = OrderLineItemReleases.LineItemID AND OrderLineItems.OrderID = OrderLineItemContainers.OrderID AND OrderLineItems.OrderID = OrderLineItemReleases.OrderID AND OrderLineItems.OrderID = Orders.OrderID AND Manifests.Manifest = ManifestContainers.Manifest AND Facilities.FacilityID = Containers.FacilityID AND Facilities.FacilityID = Manifests.FacilityID AND Facilities.FacilityID = OrderLineItemReleases.FacilityID AND Facilities.FacilityID = OrderLineItems.FacilityID
GROUP BY ManifestContainers.Manifest, Facilities.FacilityName, Manifests.StatusIND, Manifests.StatusDate, Orders.DivisionCD, Orders.OrderNumber, OrderLineItemReleases.LineItemID, OrderLineItemReleases.StyleCd, OrderLineItemReleases.ColorCD, OrderLineItemReleases.SizeCD, OrderLineItemReleases.AttributeCD
HAVING (Manifests.StatusIND='P')
ORDER BY ManifestContainers.Manifest